messages.content:
I'll build FishHunt - a production-quality Laravel fishing activity planner. This is a comprehensive build with full auth, roles/permissions, catch posts with photos, social features, and a hunt checklist planner.

<boltArtifact id="fishhunt-laravel" title="FishHunt - Fishing Activity Planner (Laravel)">

<boltAction type="shell">
composer create-project laravel/laravel fishhunt "^11.0" --prefer-dist
</boltAction>

<boltAction type="shell">
cd fishhunt && composer require laravel/breeze --dev
</boltAction>

<boltAction type="shell">
cd fishhunt && php artisan breeze:install blade
</boltAction>

<boltAction type="file" filePath="fishhunt/.env" contentType="text/plain">
APP_NAME=FishHunt
APP_ENV=local
APP_KEY=
APP_DEBUG=true
APP_URL=http://localhost:3000

LOG_CHANNEL=stack
LOG_DEPRECATIONS_CHANNEL=null
LOG_LEVEL=debug

DB_CONNECTION=pgsql
DB_HOST=127.0.0.1
DB_PORT=5432
DB_DATABASE=fishhunt
DB_USERNAME=postgres
DB_PASSWORD=postgres

BROADCAST_DRIVER=log
CACHE_DRIVER=file
FILESYSTEM_DISK=public
QUEUE_CONNECTION=sync
SESSION_DRIVER=file
SESSION_LIFETIME=120
</boltAction>

