<boltAction type="file" filePath="fishhunt/app/Models/HuntPlan.php" contentType="text/x-php">
<?php

namespace App\Models;

use Illuminate\Database\Eloquent\Model;
use Illuminate\Database\Eloquent\Relations\BelongsTo;

class HuntPlan extends Model
{
    protected $fillable = [
        'user_id', 'title', 'description', 'location', 'latitude', 'longitude',
        'planned_date', 'start_time', 'end_time', 'target_species',
        'checklist', 'briefing_data', 'status', 'notes',
    ];

    protected function casts(): array
    {
        return [
            'planned_date' => 'date',
            'target_species' => 'array',
            'checklist' => 'array',
            'briefing_data' => 'array',
            'latitude' => 'decimal:7',
            'longitude' => 'decimal:7',
        ];
    }

    public function user(): BelongsTo
    {
        return $this->belongsTo(User::class);
    }

    public function getStatusColorAttribute(): string
    {
        return match ($this->status) {
            'draft' => 'gray',
            'planned' => 'blue',
            'active' => 'green',
            'completed' => 'purple',
            'cancelled' => 'red',
            default => 'gray',
        };
    }

    public function getChecklistProgressAttribute(): int
    {
        if (!$this->checklist || count($this->checklist) === 0) return 0;
        $checked = collect($this->checklist)->where('checked', true)->count();
        return (int) round(($checked / count($this->checklist)) * 100);
    }
}
</boltAction>

<boltAction type="file" filePath="fishhunt/app/Services/BriefingService.php" contentType="text/x-php">
<?php

namespace App\Services;

use App\Models\HuntPlan;
use Carbon\Carbon;

class BriefingService
{
    public function generateBriefing(HuntPlan $plan): array
    {
        return [
            'weather' => $this->getWeatherData($plan),
            'tides' => $this->getTideData($plan),
            'species' => $this->getSpeciesData($plan),
            'conditions' => $this->getConditionsRating($plan),
            'recommendations' => $this->getRecommendations($plan),
            'generated_at' => now()->toIso8601String(),
        ];
    }

    private function getWeatherData(HuntPlan $plan): array
    {
        $date = $plan->planned_date;
        $seed = crc32($plan->location . $date->format('Y-m-d'));
        srand($seed);

        $conditions = ['Sunny', 'Partly Cloudy', 'Overcast', 'Light Rain', 'Foggy', 'Clear'];
        $windDirs = ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW'];

        $hours = [];
        $baseTemp = rand(55, 85);
        for ($h = 5; $h <= 20; $h++) {
            $tempVariation = sin(($h - 6) * M_PI / 14) * 12;
            $hours[] = [
                'hour' => sprintf('%02d:00', $h),
                'temp' => round($baseTemp + $tempVariation),
                'condition' => $conditions[array_rand($conditions)],
                'wind_speed' => rand(2, 18),
                'wind_dir' => $windDirs[array_rand($windDirs)],
                'humidity' => rand(40, 85),
                'precipitation' => rand(0, 30),
            ];
        }

        return [
            'summary' => $conditions[array_rand($conditions)],
            'high_temp' => $baseTemp + 12,
            'low_temp' => $baseTemp - 5,
            'wind_speed' => rand(3, 15),
            'wind_dir' => $windDirs[array_rand($windDirs)],
            'humidity' => rand(45, 80),
            'uv_index' => rand(2, 10),
            'sunrise' => '06:' . sprintf('%02d', rand(10, 45)) . ' AM',
            'sunset' => '07:' . sprintf('%02d', rand(15, 55)) . ' PM',
            'barometric_pressure' => round(29.5 + (rand(0, 100) / 100), 2),
            'hourly' => $hours,
        ];
    }

    private function getTideData(HuntPlan $plan): array
    {
        $seed = crc32($plan->location . $plan->planned_date->format('Y-m-d') . 'tide');
        srand($seed);

        $tides = [];
        $baseHour = rand(0, 5);
        for ($i = 0; $i < 4; $i++) {
            $hour = ($baseHour + ($i * 6) + rand(0, 2)) % 24;
            $tides[] = [
                'type' => $i % 2 === 0 ? 'high' : 'low',
                'time' => sprintf('%02d:%02d', $hour, rand(0, 59)),
                'height' => round(($i % 2 === 0 ? rand(35, 65) : rand(5, 20)) / 10, 1),
            ];
        }

        usort($tides, fn($a, $b) => strcmp($a['time'], $b['time']));

        return [
            'tides' => $tides,
            'current' => ['speed' => round(rand(5, 30) / 10, 1), 'direction' => ['N', 'S', 'E', 'W'][rand(0, 3)]],
            'water_temp' => rand(58, 78),
            'water_clarity' => ['Clear', 'Slightly Murky', 'Murky', 'Stained'][rand(0, 3)],
            'moon_phase' => ['New Moon', 'Waxing Crescent', 'First Quarter', 'Waxing Gibbous', 'Full Moon', 'Waning Gibbous', 'Last Quarter', 'Waning Crescent'][rand(0, 7)],
        ];
    }

    private function getSpeciesData(HuntPlan $plan): array
    {
        $allSpecies = [
            ['name' => 'Largemouth Bass', 'activity' => 'High', 'best_time' => 'Early Morning', 'depth' => '3-8 ft', 'technique' => 'Topwater, Crankbait', 'bait' => 'Plastic worms, Spinnerbait'],
            ['name' => 'Smallmouth Bass', 'activity' => 'Moderate', 'best_time' => 'Morning', 'depth' => '5-15 ft', 'technique' => 'Drop shot, Jig', 'bait' => 'Crawfish, Tube jig'],
            ['name' => 'Rainbow Trout', 'activity' => 'High', 'best_time' => 'Dawn/Dusk', 'depth' => '2-6 ft', 'technique' => 'Fly fishing, Spinning', 'bait' => 'Dry flies, PowerBait'],
            ['name' => 'Walleye', 'activity' => 'Moderate', 'best_time' => 'Evening', 'depth' => '10-25 ft', 'technique' => 'Jigging, Trolling', 'bait' => 'Minnows, Leeches'],
            ['name' => 'Bluegill', 'activity' => 'Very High', 'best_time' => 'Midday', 'depth' => '2-8 ft', 'technique' => 'Bobber fishing', 'bait' => 'Worms, Crickets'],
            ['name' => 'Channel Catfish', 'activity' => 'High', 'best_time' => 'Night', 'depth' => '8-20 ft', 'technique' => 'Bottom fishing', 'bait' => 'Stink bait, Cut bait'],
            ['name' => 'Northern Pike', 'activity' => 'Moderate', 'best_time' => 'Morning', 'depth' => '4-12 ft', 'technique' => 'Casting, Trolling', 'bait' => 'Spoons, Large minnows'],
            ['name' => 'Crappie', 'activity' => 'High', 'best_time' => 'Early Morning', 'depth' => '5-15 ft', 'technique' => 'Jigging', 'bait' => 'Small jigs, Minnows'],
            ['name' => 'Striped Bass', 'activity' => 'Moderate', 'best_time' => 'Dawn', 'depth' => '15-40 ft', 'technique' => 'Live bait, Trolling', 'bait' => 'Bunker, Eels'],
            ['name' => 'Redfish', 'activity' => 'High', 'best_time' => 'Incoming Tide', 'depth' => '2-6 ft', 'technique' => 'Sight casting', 'bait' => 'Shrimp, Cut mullet'],
        ];

        $targetSpecies = $plan->target_species ?? [];
        $species = [];

        if (!empty($targetSpecies)) {
            foreach ($allSpecies as $s) {
                if (in_array($s['name'], $targetSpecies)) {
                    $species[] = $s;
                }
            }
        }

        if (empty($species)) {
            shuffle($allSpecies);
            $species = array_slice($allSpecies, 0, rand(3, 5));
        }

        return $species;
    }

    private function getConditionsRating(HuntPlan $plan): array
    {
        $seed = crc32($plan->location . $plan->planned_date->format('Y-m-d') . 'rating');
        srand($seed);

        $overall = rand(45, 95);

        return [
            'overall' => $overall,
            'label' => match (true) {
                $overall >= 80 => 'Excellent',
                $overall >= 60 => 'Good',
                $overall >= 40 => 'Fair',
                default => 'Poor',
            },
            'factors' => [
                ['name' => 'Weather', 'score' => rand(50, 95), 'icon' => 'cloud-sun'],
                ['name' => 'Barometric Pressure', 'score' => rand(40, 90), 'icon' => 'gauge'],
                ['name' => 'Moon Phase', 'score' => rand(30, 95), 'icon' => 'moon'],
                ['name' => 'Tide/Current', 'score' => rand(45, 90), 'icon' => 'waves'],
                ['name' => 'Water Temperature', 'score' => rand(50, 95), 'icon' => 'thermometer'],
                ['name' => 'Wind', 'score' => rand(35, 90), 'icon' => 'wind'],
            ],
        ];
    }

    private function getRecommendations(HuntPlan $plan): array
    {
        $tips = [
            'Fish the shaded areas during peak sun hours for better results.',
            'Barometric pressure is falling — fish tend to feed more aggressively before a front.',
            'Try slower presentations in cooler water temperatures.',
            'Focus on structure and drop-offs where fish congregate.',
            'The incoming tide will push baitfish into the shallows — follow the food.',
            'Use natural-colored baits in clear water conditions.',
            'Wind-blown banks concentrate baitfish — cast into the wind.',
            'Early morning topwater action should be excellent.',
            'Consider downsizing your line for finicky fish.',
            'Moon phase suggests increased nighttime feeding activity.',
        ];

        shuffle($tips);
        return array_slice($tips, 0, rand(3, 5));
    }
}
