<script>
function checklistManager(initialChecklist, planId) {
    return {
        checklist: initialChecklist,
        progress: 0,
        init() {
            this.updateProgress();
        },
        toggleItem(index) {
            this.checklist[index].checked = !this.checklist[index].checked;
            this.updateProgress();
            this.save();
        },
        updateProgress() {
            if (this.checklist.length === 0) { this.progress = 0; return; }
            const checked = this.checklist.filter(i => i.checked).length;
            this.progress = Math.round((checked / this.checklist.length) * 100);
        },
        save() {
            fetch(`/plans/${planId}/checklist`, {
                method: 'PATCH',
                headers: {
                    'Content-Type': 'application/json',
                    'X-CSRF-TOKEN': document.querySelector('meta[name="csrf-token"]').content,
                    'Accept': 'application/json',
                },
                body: JSON.stringify({ checklist: this.checklist }),
            });
        }
    };
}
</script>
