<boltAction type="file" filePath="fishhunt/app/Http/Controllers/FeedController.php" contentType="text/x-php">
<?php

namespace App\Http\Controllers;

use App\Models\CatchPost;
use Illuminate\Http\Request;

class FeedController extends Controller
{
    public function index(Request $request)
    {
        $query = CatchPost::with(['user', 'photos', 'likes', 'comments'])
            ->where('is_published', true)
            ->withCount(['likes', 'allComments']);

        if ($search = $request->get('search')) {
            $query->where(function ($q) use ($search) {
                $q->where('title', 'ilike', "%{$search}%")
                  ->orWhere('species', 'ilike', "%{$search}%")
                  ->orWhere('location', 'ilike', "%{$search}%");
            });
        }

        if ($species = $request->get('species')) {
            $query->where('species', $species);
        }

        $sort = $request->get('sort', 'latest');
        $query = match ($sort) {
            'popular' => $query->orderByDesc('likes_count'),
            'weight' => $query->orderByDesc('weight'),
            default => $query->orderByDesc('created_at'),
        };

        $posts = $query->paginate(12)->withQueryString();

        $topSpecies = CatchPost::where('is_published', true)
            ->selectRaw('species, count(*) as count')
            ->groupBy('species')
            ->orderByDesc('count')
            ->limit(10)
            ->pluck('count', 'species');

        return view('feed.index', compact('posts', 'topSpecies'));
    }
}
</boltAction>

<boltAction type="file" filePath="fishhunt/app/Http/Controllers/CatchPostController.php" contentType="text/x-php">
<?php

namespace App\Http\Controllers;

use App\Models\CatchPost;
use App\Models\CatchPhoto;
use Illuminate\Http\Request;
use Illuminate\Support\Facades\Storage;

class CatchPostController extends Controller
{
    public function show(CatchPost $catchPost)
    {
        $this->authorize('view', $catchPost);

        $catchPost->load([
            'user', 'photos',
            'comments' => fn($q) => $q->with(['user', 'replies.user'])->where('is_hidden', false),
        ])->loadCount(['likes', 'allComments']);

        $relatedPosts = CatchPost::where('species', $catchPost->species)
            ->where('id', '!=', $catchPost->id)
            ->where('is_published', true)
            ->with(['user', 'photos'])
            ->withCount('likes')
            ->latest()
            ->limit(4)
            ->get();

        return view('catches.show', compact('catchPost', 'relatedPosts'));
    }

    public function create()
    {
        return view('catches.create');
    }

    public function store(Request $request)
    {
        $validated = $request->validate([
            'title' => 'required|string|max:255',
            'description' => 'nullable|string|max:2000',
            'species' => 'required|string|max:100',
            'weight' => 'nullable|numeric|min:0|max:9999',
            'length' => 'nullable|numeric|min:0|max:999',
            'location' => 'nullable|string|max:255',
            'latitude' => 'nullable|numeric|between:-90,90',
            'longitude' => 'nullable|numeric|between:-180,180',
            'technique' => 'nullable|string|max:100',
            'bait' => 'nullable|string|max:100',
            'caught_at' => 'nullable|date',
            'photos' => 'nullable|array|max:5',
            'photos.*' => 'image|mimes:jpg,jpeg,png,webp|max:5120',
        ]);

        $post = $request->user()->catchPosts()->create($validated);

        if ($request->hasFile('photos')) {
            foreach ($request->file('photos') as $index => $photo) {
                $path = $photo->store('catches/' . $post->id, 'public');
                $post->photos()->create([
                    'path' => $path,
                    'filename' => $photo->getClientOriginalName(),
                    'sort_order' => $index,
                ]);
            }
        }

        return redirect()->route('catches.show', $post)
            ->with('success', 'Catch posted successfully! 🎣');
    }

    public function edit(CatchPost $catchPost)
    {
        $this->authorize('update', $catchPost);
        $catchPost->load('photos');
        return view('catches.edit', compact('catchPost'));
    }

    public function update(Request $request, CatchPost $catchPost)
    {
        $this->authorize('update', $catchPost);

        $validated = $request->validate([
            'title' => 'required|string|max:255',
            'description' => 'nullable|string|max:2000',
            'species' => 'required|string|max:100',
            'weight' => 'nullable|numeric|min:0|max:9999',
            'length' => 'nullable|numeric|min:0|max:999',
            'location' => 'nullable|string|max:255',
            'technique' => 'nullable|string|max:100',
            'bait' => 'nullable|string|max:100',
            'caught_at' => 'nullable|date',
            'photos' => 'nullable|array|max:5',
            'photos.*' => 'image|mimes:jpg,jpeg,png,webp|max:5120',
            'remove_photos' => 'nullable|array',
            'remove_photos.*' => 'integer|exists:catch_photos,id',
        ]);

        $catchPost->update($validated);

        if ($request->has('remove_photos')) {
            $photos = CatchPhoto::whereIn('id', $request->remove_photos)
                ->where('catch_post_id', $catchPost->id)->get();
            foreach ($photos as $photo) {
                Storage::disk('public')->delete($photo->path);
                $photo->delete();
            }
        }

        if ($request->hasFile('photos')) {
            $maxOrder = $catchPost->photos()->max('sort_order') ?? -1;
            foreach ($request->file('photos') as $index => $photo) {
                $path = $photo->store('catches/' . $catchPost->id, 'public');
                $catchPost->photos()->create([
                    'path' => $path,
                    'filename' => $photo->getClientOriginalName(),
                    'sort_order' => $maxOrder + $index + 1,
                ]);
            }
        }

        return redirect()->route('catches.show', $catchPost)
            ->with('success', 'Catch updated successfully!');
    }

    public function destroy(CatchPost $catchPost)
    {
        $this->authorize('delete', $catchPost);

        foreach ($catchPost->photos as $photo) {
            Storage::disk('public')->delete($photo->path);
        }

        $catchPost->delete();

        return redirect()->route('feed')
            ->with('success', 'Catch deleted successfully.');
    }
}
</boltAction>

