<?php

namespace App\Http\Controllers;

use App\Models\CatchPost;
use Illuminate\Http\Request;

class LikeController extends Controller
{
    public function toggle(Request $request, CatchPost $catchPost)
    {
        $user = $request->user();
        $existing = $catchPost->likes()->where('user_id', $user->id)->first();

        if ($existing) {
            $existing->delete();
            $liked = false;
        } else {
            $catchPost->likes()->create(['user_id' => $user->id]);
            $liked = true;
        }

        if ($request->wantsJson()) {
