<boltAction type="file" filePath="fishhunt/app/Http/Controllers/AdminController.php" contentType="text/x-php">
<?php

namespace App\Http\Controllers;

use App\Models\Report;
use App\Models\User;
use App\Models\CatchPost;
use Illuminate\Http\Request;

class AdminController extends Controller
{
    public function dashboard()
    {
        $stats = [
            'users' => User::count(),
            'posts' => CatchPost::count(),
            'reports_pending' => Report::where('status', 'pending')->count(),
            'reports_total' => Report::count(),
        ];

        $recentReports = Report::with(['user', 'reportable'])
            ->where('status', 'pending')
            ->latest()
            ->limit(10)
            ->get();

        $recentUsers = User::with('roles')
            ->latest()
            ->limit(10)
            ->get();

        return view('admin.dashboard', compact('stats', 'recentReports', 'recentUsers'));
    }

    public function reports(Request $request)
    {
        $query = Report::with(['user', 'reportable', 'reviewer']);

        if ($status = $request->get('status')) {
            $query->where('status', $status);
        } else {
            $query->where('status', 'pending');
        }

        $reports = $query->latest()->paginate(20);

        return view('admin.reports', compact('reports'));
    }

    public function resolveReport(Request $request, Report $report)
    {
        $validated = $request->validate([
            'status' => 'required|in:reviewed,resolved,dismissed',
            'resolution_note' => 'nullable|string|max:500',
        ]);

        $report->update([
            'status' => $validated['status'],
            'resolution_note' => $validated['resolution_note'] ?? null,
            'reviewed_by' => $request->user()->id,
        ]);

        return back()->with('success', 'Report updated.');
    }

    public function users(Request $request)
    {
        $users = User::with('roles')
            ->withCount(['catchPosts', 'comments'])
            ->when($request->search, fn($q, $s) => $q->where('name', 'ilike', "%{$s}%")->orWhere('email', 'ilike', "%{$s}%"))
            ->latest()
            ->paginate(20);

        return view('admin.users', compact('users'));
    }

    public function toggleRole(Request $request, User $user)
    {
        $validated = $request->validate([
            'role_slug' => 'required|string|exists:roles,slug',
        ]);

        $role = \App\Models\Role::where('slug', $validated['role_slug'])->first();

        if ($user->roles()->where('role_id', $role->id)->exists()) {
            $user->roles()->detach($role->id);
            $message = "Removed {$role->name} role from {$user->name}.";
        } else {
            $user->roles()->attach($role->id);
            $message = "Assigned {$role->name} role to {$user->name}.";
        }

        return back()->with('success', $message);
    }
}
</boltAction>

