<?php

namespace Database\Seeders;

use App\Models\Permission;
use App\Models\Role;
use Illuminate\Database\Seeder;

class RolePermissionSeeder extends Seeder
{
    public function run(): void
    {
        // Create roles
        $admin = Role::create(['name' => 'Administrator', 'slug' => 'admin', 'description' => 'Full system access']);
        $mod = Role::create(['name' => 'Moderator', 'slug' => 'moderator', 'description' => 'Content moderation access']);
        $member = Role::create(['name' => 'Member', 'slug' => 'member', 'description' => 'Standard member']);

        // Create permissions
        $permissions = [
            'manage-users' => 'Manage user accounts and roles',
            'manage-posts' => 'Edit and delete any post',
            'manage-comments' => 'Edit, hide, and delete any comment',
            'manage-reports' => 'Review and resolve reports',
            'view-admin' => 'Access admin dashboard',
            'create-post' => 'Create catch posts',
            'edit-own-post' => 'Edit own catch posts',
            'delete-own-post' => 'Delete own catch posts',
            'create-comment' => 'Create comments',
            'create-plan' => 'Create hunt plans',
            'report-content' => 'Report inappropriate content',
        ];

        $permModels = [];
        foreach ($permissions as $slug => $desc) {
            $permModels[$slug] = Permission::create([
                'name' => ucwords(str_replace('-', ' ', $slug)),
                'slug' => $slug,
                'description' => $desc,
            ]);
        }

        // Assign permissions
        $admin->permissions()->attach(array_values(array_map(fn($p) => $p->id, $permModels)));

        $mod->permissions()->attach([
            $permModels['manage-posts']->id,
            $permModels['manage-comments']->id,
            $permModels['manage-reports']->id,
            $permModels['view-admin']->id,
            $permModels['create-post']->id,
            $permModels['edit-own-post']->id,
            $permModels['delete-own-post']->id,
            $permModels['create-comment']->id,
            $permModels['create-plan']->id,
            $permModels['report-content']->id,
        ]);

        $member->permissions()->attach([
            $permModels['create-post']->id,
            $permModels['edit-own-post']->id,
            $permModels['delete-own-post']->id,
            $permModels['create-comment']->id,
            $permModels['create-plan']->id,
            $permModels['report-content']->id,
        ]);
    }
}
